DetectionRule.DetectionLogic:
let KnownDumperSignatures = dynamic([ "MiniDumpWriteDump", "MiniDump", "Dumpert", "SafetyKatz", "HandleKatz", "SharpKatz", "Rubeus", "Mimikatz", "sekurlsa", "comsvcs.dll", "rundll32.exe.*comsvcs", "procdump", "-ma" ]);
let SuspiciousAccessMasks = dynamic([ "0x1fffff", "0x1010", "0x143a", "0x1f3fff", "PROCESS_ALL_ACCESS" ]);
let TargetProcessNames = dynamic(["lsass.exe", "LSASS.exe"]);
// Detect direct process access to LSASS DeviceProcessEvents | where Timestamp > ago(1h) | where TargetProcessName in~ (TargetProcessNames) and InitiatingProcessFileName !in~ ("lsass.exe", "svchost.exe", "services.exe", "MsMpEng.exe") and InitiatingProcessFileName !startswith "conhost" | where ProcessCommandLine has_any (KnownDumperSignatures) or ProcessCommandLine matches regex @".*(0x[0-9a-fA-F]+).*" | extend AccessMask = extract(@"0x[0-9a-fA-F]+", 0, ProcessCommandLine) | extend DumperTechnique = case( ProcessCommandLine has "MiniDumpWriteDump", "MiniDump API", ProcessCommandLine has "comsvcs.dll", "Comsvcs MiniDump", ProcessCommandLine has "Dumpert", "Direct Syscall", ProcessCommandLine has "procdump", "ProcDump", "Unknown Dumper" ) | summarize DumpAttempts = count(), Techniques = makeset(DumperTechnique), Commands = makeset(ProcessCommandLine) by DeviceId, InitiatingProcessFileName, TargetProcessName, AccountName
// Also detect via API monitoring (EDR behavioral detection) union ( DeviceApiCalls | where Timestamp > ago(1h) | where ApiName in~ ("OpenProcess", "ReadProcessMemory", "MiniDumpWriteDump") and TargetProcessName in~ (TargetProcessNames) and InitiatingProcessFileName !in~ ("MsMpEng.exe", "svchost.exe", "services.exe") | extend RiskLevel = case( ApiName == "MiniDumpWriteDump", "Critical", ApiName == "ReadProcessMemory" and TargetProcessName == "lsass.exe", "High", "Medium" ) | where RiskLevel in~ ("Critical", "High") | summarize ApiCalls = count() by DeviceId, InitiatingProcessFileName, RiskLevel | where ApiCalls >= 3 ) | extend FinalSeverity = case( DumpAttempts >= 3 or ApiCalls >= 5, "Critical", DumpAttempts >= 1 or ApiCalls >= 3, "High", "Medium" ) | project-reorder Timestamp, DeviceId, FinalSeverity, InitiatingProcessFileName, DumpAttempts

let SAMHivePaths = dynamic([ "\\Registry\\Machine\\SAM", "\\REGISTRY\\MACHINE\\SAM", "HKLM:\\SAM", "HKLM\\SAM" ]);
let SuspiciousRegistryOps = dynamic([ "reg.exe save", "reg save", "reg export", "regedit.exe /e", "regedit /e", "Copy-Item HKLM:\\SAM", "Get-Item HKLM:\\SAM", "reg.exe copy" ]);
// Detect registry export operations DeviceProcessEvents | where Timestamp > ago(2h) | where (ProcessCommandLine has_any (SuspiciousRegistryOps) and (ProcessCommandLine contains "SAM" or ProcessCommandLine contains "sam")) or (FileName == "regedit.exe" and ProcessCommandLine contains "/e") or (FileName == "reg.exe" and ProcessCommandLine contains "save" and ProcessCommandLine contains "sam") | extend OperationType = case( ProcessCommandLine contains "save", "Registry Save", ProcessCommandLine contains "export", "Registry Export", ProcessCommandLine contains "/e", "Registry Extract", "Other" ) | where OperationType != "Other" | summarize RegistryOps = count(), Commands = makeset(ProcessCommandLine) by DeviceId, FileName, InitiatingProcessFileName, AccountName, OperationType
// Also detect shadow copy creation for SAM extraction union ( DeviceProcessEvents | where Timestamp > ago(2h) | where FileName in~ ("vssadmin.exe", "wmic.exe", "powershell.exe") and ProcessCommandLine has "shadow" and ProcessCommandLine has "copy" | extend ShadowOp = case( ProcessCommandLine contains "create shadow", "Shadow Copy Creation", ProcessCommandLine contains "shadowcopy", "Shadow Copy Access", "Other" ) | where ShadowOp != "Other" | summarize ShadowOps = count() by DeviceId, FileName, InitiatingProcessCommandLine ) | extend FinalRisk = case( RegistryOps >= 2 or ShadowOps >= 1, "Critical", RegistryOps == 1, "High", "Medium" ) | where FinalRisk in~ ("Critical", "High") | project-reorder Timestamp, DeviceId, FinalRisk, FileName, AccountName

let BrowserPaths = dynamic([ "Login Data", "Cookies", "Web Data", "History", "chrome\\User Data", "firefox\\profiles", "Microsoft\\Edge\\User Data", "BraveSoftware\\Brave-Browser" ]);
let CredentialStealers = dynamic([ "mimikatz", "LaZagne", "BrowserPwdDump", "SharpChrome", "SharpChromium", "NirSoft", "WebBrowserPassView", "PasswordFox" ]);
// Detect access to browser credential databases DeviceFileEvents | where Timestamp > ago(2h) | where FolderPath has_any (BrowserPaths) and (FileName contains "Login Data" or FileName contains "Cookies" or FileName contains "Web Data") and ActionType in~ ("FileCreated", "FileRead", "FileModified") and InitiatingProcessFileName !in~ ("chrome.exe", "msedge.exe", "firefox.exe", "brave.exe") | extend BrowserType = case( FolderPath contains "chrome", "Chrome", FolderPath contains "firefox", "Firefox", FolderPath contains "Edge", "Edge", "Unknown" ) | summarize CredentialAccess = count(), UniqueFiles = dcount(FileName) by DeviceId, InitiatingProcessFileName, BrowserType, AccountName | where CredentialAccess >= 3
// Also detect credential harvesting tools union ( DeviceProcessEvents | where Timestamp > ago(2h) | where FileName in~ (CredentialStealers) or ProcessCommandLine has_any (CredentialStealers) | extend StealerType = case( FileName contains "mimikatz", "Mimikatz", FileName contains "LaZagne", "LaZagne", FileName contains "Sharp", "SharpBrowser", "Unknown Stealer" ) | summarize StealerRuns = count() by DeviceId, FileName, StealerType ) | extend FinalRisk = case( StealerRuns >= 1, "Critical", CredentialAccess >= 5, "High", CredentialAccess >= 3, "Medium", "Low" ) | where FinalRisk in~ ("High", "Critical") | project-reorder Timestamp, DeviceId, FinalRisk, CredentialAccess, StealerType

let ProcdumpIndicators = dynamic([ "-ma", "-accepteula", "-64", "lsass", "procdump.*lsass", "procdump.*-ma", "procdump.*accepteula" ]);
// Detect ProcDump targeting LSASS DeviceProcessEvents | where Timestamp > ago(1h) | where FileName in~ ("procdump.exe", "procdump64.exe", "procdump64a.exe", "procdump32.exe") | extend CommandLower = tolower(ProcessCommandLine) | where CommandLower has_any (ProcdumpIndicators) or (CommandLower contains "lsass" and CommandLower contains "-ma") or (CommandLower contains "accepteula" and CommandLower contains "lsass") | extend DumpType = case( CommandLower contains "-ma" and CommandLower contains "lsass", "Full LSASS Dump", CommandLower contains "lsass", "LSASS Targeted", "Other Dump" ) | where DumpType != "Other Dump" | summarize DumpAttempts = count(), CommandLines = makeset(ProcessCommandLine) by DeviceId, InitiatingProcessFileName, AccountName, DumpType | where DumpAttempts >= 1
// Also detect renamed procdump or similar tools union ( DeviceProcessEvents | where Timestamp > ago(1h) | where ProcessCommandLine has_any (ProcdumpIndicators) and FileName !in~ ("procdump.exe", "procdump64.exe") and InitiatingProcessFileName !in~ ("MsMpEng.exe", "svchost.exe") | extend RenamedTool = case( ProcessCommandLine contains "lsass", "Renamed Procdump", ProcessCommandLine contains "-ma", "Memory Dumper", "Unknown" ) | summarize RenamedRuns = count() by DeviceId, FileName, RenamedTool ) | extend FinalRisk = case( DumpAttempts >= 2 or RenamedRuns >= 1, "High", DumpAttempts == 1, "Medium", "Low" ) | where FinalRisk in~ ("High", "Medium") | project-reorder Timestamp, DeviceId, FinalRisk, DumpAttempts, RenamedTool

let DpapiTools = dynamic([ "SharpDPAPI", "Mimikatz", "Rubeus", "SafetyKatz", "dpapi::masterkey", "dpapi::cred", "dpapi::vault", "Backup-VolumeShadowCopy", "Get-DPAPIPolicy", "Get-Content -Path", "Get-ItemProperty", "HKEY_CURRENT_USER" ]);
let KeyExtractionIndicators = dynamic([ "master.key", "Preferred Master Key", "Protect Master Key", "DPAPI_SYSTEM", "LSA Secret", "CredHist", "DPAPI" ]);
// Detect PowerShell DPAPI extraction attempts DeviceProcessEvents | where Timestamp > ago(1h) | where InitiatingProcessFileName endswith "powershell.exe" or InitiatingProcessFileName endswith "pwsh.exe" | where ProcessCommandLine has_any (DpapiTools) or ProcessCommandLine has_any (KeyExtractionIndicators) | where ProcessCommandLine matches regex @"(?i)(dpapi|masterkey|credential|password|secret)" | extend ExtractionMethod = case( ProcessCommandLine has "SharpDPAPI", "DPAPI PowerShell Module", ProcessCommandLine has "Mimikatz", "Mimikatz DPAPI", ProcessCommandLine has "Backup-VolumeShadowCopy", "Volume Shadow Copy + DPAPI", ProcessCommandLine has "Get-DPAPIPolicy", "DPAPI Policy Export", "Generic DPAPI Extraction" ) | summarize EventCount = count(), AffectedUsers = dcount(AccountName), SampleCommands = make_set(ProcessCommandLine, 3), ToolsUsed = make_set(InitiatingProcessFileName, 5) by bin(Timestamp, 5m), DeviceName, ExtractionMethod | where EventCount >= 2

let BrowserCookiePaths = dynamic([ "\\Local\\Google\\Chrome\\User Data\\Default\\Cookies", "\\Local\\Google\\Chrome\\User Data\\*\\Network\\Cookies", "\\Local\\Microsoft\\Edge\\User Data\\Default\\Cookies", "\\Roaming\\Mozilla\\Firefox\\Profiles\\*\\cookies.sqlite", "\\Local\\BraveSoftware\\Brave-Browser\\User Data\\*\\Network\\Cookies", "Browser Cookies", "cookies.sqlite", "Cookies", "Login Data" ]);
let CookieExportTools = dynamic([ "SharpChrome", "SharpChromium", "BrowserCredentials", "ChromeCookies", "firefox_decrypt", "Cookie Editor", "browser-cookies", "editthiscookie", "Get-ChromeCookies" ]);
let SuspiciousExtensions = dynamic([ "EditThisCookie", "Cookie Editor", "Scraper", "Get cookies.txt", "cookies.txt" ]);
// Detect file access to browser cookie databases DeviceFileEvents | where Timestamp > ago(1h) | where ActionType in ("FileCreated", "FileModified", "FileDeleted") | where FolderPath has_any (BrowserCookiePaths) or FileName in ("cookies.sqlite", "Cookies", "Login Data", "Bookmarks") | where not(InitiatingProcessFileName in~ ( "chrome.exe", "msedge.exe", "firefox.exe", "brave.exe", "opera.exe", "vivaldi.exe", "GoogleUpdate.exe" )) | extend CookieActivity = case( FileName endswith "ookies", "Browser Cookie Database", FileName endswith "sqlite", "SQLite Cookie Export", "Unknown Cookie Activity" ) | summarize EventCount = count(), AffectedBrowsers = dcount(FolderPath), CookieFiles = make_set(FileName, 5), Tools = make_set(InitiatingProcessFileName, 5) by bin(Timestamp, 5m), DeviceName, UserName, CookieActivity | where EventCount >= 3
union
// Detect PowerShell/browser extension cookie extraction DeviceProcessEvents | where Timestamp > ago(1h) | where InitiatingProcessFileName endswith "powershell.exe" or InitiatingProcessFileName endswith "pwsh.exe" or InitiatingProcessFileName endswith "wscript.exe" or InitiatingProcessFileName endswith "cscript.exe" | where ProcessCommandLine has_any (CookieExportTools) or ProcessCommandLine has "cookie" and ProcessCommandLine has ("export" or "steal" or "dump") or ProcessCommandLine matches regex @"(?i)(chromium|firefox|chrome).*(cookie|token|session)" | summarize EventCount = count(), AffectedUsers = dcount(AccountName), Commands = make_set(ProcessCommandLine, 3) by bin(Timestamp, 5m), DeviceName, ExtractionTool = InitiatingProcessFileName | where EventCount >= 2
